// ── Time range helpers ────────────────────────────────────────────────────────

const RANGES = [
  { label: '1H', days: 1 },
  { label: '24H', days: 1 },
  { label: '7D', days: 7 },
  { label: '30D', days: 30 },
  { label: '90D', days: 90 },
] as const;
type RangeLabel = typeof RANGES[number]['label'];

function relativeTime(ts: string): string {
  const diffMs = Date.now() - new Date(ts).getTime();
  const secs = Math.floor(diffMs / 1000);
  if (secs < 60) return `${secs}s`;
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h`;
  return `${Math.floor(hrs / 24)}d`;
}

// ── SVG chart components ──────────────────────────────────────────────────────

function Sparkline({
  points,
  color = 'var(--brand-500)',
  width = 88,
  height = 28,
}: {
  points: number[];
  color?: string;
  width?: number;
  height?: number;
}) {
  if (!points || points.length === 0) {
    return <svg className="kpi__spark" width={width} height={height} />;
  }
  const max = Math.max(...points, 1);
  const min = Math.min(...points, 0);
  const range = max - min || 1;
  const step = points.length > 1 ? width / (points.length - 1) : width;
  const coords = points.map((v, i) => [i * step, height - ((v - min) / range) * (height - 4) - 2]);
  const d = coords.map((c, i) => (i ? 'L' : 'M') + c[0].toFixed(1) + ' ' + c[1].toFixed(1)).join(' ');
  const area = d + ` L ${width} ${height} L 0 ${height} Z`;
  const id = 'sg-' + color.replace(/[^a-z0-9]/gi, '').slice(0, 8) + '-' + points.length;
  return (
    <svg
      className="kpi__spark"
      viewBox={`0 0 ${width} ${height}`}
      preserveAspectRatio="none"
      width={width}
      height={height}
    >
      <defs>
        <linearGradient id={id} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.18" />
          <stop offset="100%" stopColor={color} stopOpacity="0" />
        </linearGradient>
      </defs>
      <path d={area} fill={`url(#${id})`} />
      <path d={d} fill="none" stroke={color} strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

function LineChart({
  series,
  height = 240,
  days = 30,
}: {
  series: { name: string; color: string; data: number[] }[];
  height?: number;
  days?: number;
}) {
  const w = 1000;
  const h = height;
  const pad = { top: 16, right: 16, bottom: 28, left: 38 };
  const innerW = w - pad.left - pad.right;
  const innerH = h - pad.top - pad.bottom;
  const allMax = Math.max(...series.flatMap(s => s.data), 1);
  const allMin = 0;
  const range = allMax - allMin || 1;
  const step = innerW / Math.max(days - 1, 1);
  const xAt = (i: number) => pad.left + i * step;
  const yAt = (v: number) => pad.top + innerH - ((v - allMin) / range) * innerH;
  const yTicks = 4;
  const tickValues = Array.from({ length: yTicks + 1 }, (_, i) => Math.round((allMax / yTicks) * i));
  const xLabels = [0, Math.floor(days / 4), Math.floor(days / 2), Math.floor(days * 3 / 4), days - 1].filter((v, i, a) => a.indexOf(v) === i);

  return (
    <svg viewBox={`0 0 ${w} ${h}`} width="100%" height={h} style={{ display: 'block' }}>
      {tickValues.map((v, i) => (
        <g key={i}>
          <line
            x1={pad.left} x2={w - pad.right}
            y1={yAt(v)} y2={yAt(v)}
            stroke="var(--border)" strokeDasharray={i === 0 ? '' : '2 4'}
          />
          <text
            x={pad.left - 8} y={yAt(v) + 3}
            fontSize="10.5" fill="var(--text-subtle)"
            fontFamily="var(--font-mono)" textAnchor="end"
          >
            {v}
          </text>
        </g>
      ))}
      {xLabels.map(i => (
        <text
          key={i} x={xAt(i)} y={h - 8}
          fontSize="10.5" fill="var(--text-subtle)"
          fontFamily="var(--font-mono)" textAnchor="middle"
        >
          {`d-${days - 1 - i}`}
        </text>
      ))}
      {series.map(s => {
        const safeData = s.data.length > 0 ? s.data : Array(days).fill(0);
        const id = 'lg-' + s.name.replace(/\s/g, '');
        const d = safeData.map((v, i) => (i ? 'L' : 'M') + xAt(i) + ' ' + yAt(v)).join(' ');
        const area = d + ` L ${xAt(safeData.length - 1)} ${pad.top + innerH} L ${xAt(0)} ${pad.top + innerH} Z`;
        return (
          <g key={s.name}>
            <defs>
              <linearGradient id={id} x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor={s.color} stopOpacity="0.18" />
                <stop offset="100%" stopColor={s.color} stopOpacity="0" />
              </linearGradient>
            </defs>
            <path d={area} fill={`url(#${id})`} />
            <path d={d} stroke={s.color} strokeWidth="1.8" fill="none" strokeLinecap="round" strokeLinejoin="round" />
          </g>
        );
      })}
    </svg>
  );
}

type PerfMetric = 'avg' | 'p50' | 'p95' | 'p99';

function PerfHistogram({
  buckets,
  metric = 'avg',
  height = 200,
}: {
  buckets: HomePerfBucket[];
  metric?: PerfMetric;
  height?: number;
}) {
  if (!buckets || buckets.length === 0) {
    return (
      <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <span className="muted" style={{ fontSize: 13 }}>No execution data yet</span>
      </div>
    );
  }
  const w = 1000;
  const h = height;
  const pad = { top: 14, right: 16, bottom: 28, left: 38 };
  const innerW = w - pad.left - pad.right;
  const innerH = h - pad.top - pad.bottom;

  const getValue = (b: HomePerfBucket) => {
    if (metric === 'p50') return b.p50Ms;
    if (metric === 'p95') return b.p95Ms;
    if (metric === 'p99') return b.p99Ms;
    return b.avgMs;
  };

  const values = buckets.map(getValue);
  const max = Math.max(...values, 1);
  const bw = innerW / buckets.length;

  // p95 threshold line at 65th percentile of max
  const p95Line = max * 0.65;

  return (
    <svg viewBox={`0 0 ${w} ${h}`} width="100%" height={h} style={{ display: 'block' }}>
      {[0, 0.25, 0.5, 0.75, 1].map((t, i) => (
        <g key={i}>
          <line
            x1={pad.left} x2={w - pad.right}
            y1={pad.top + innerH * (1 - t)} y2={pad.top + innerH * (1 - t)}
            stroke="var(--border)" strokeDasharray={t === 0 ? '' : '2 4'}
          />
          <text
            x={pad.left - 8} y={pad.top + innerH * (1 - t) + 3}
            fontSize="10.5" fill="var(--text-subtle)"
            fontFamily="var(--font-mono)" textAnchor="end"
          >
            {Math.round(max * t)}ms
          </text>
        </g>
      ))}
      {buckets.map((b, i) => {
        const val = getValue(b);
        const bh = (val / max) * innerH;
        const x = pad.left + i * bw + 2;
        const y = pad.top + innerH - bh;
        // Color bars: p99 red, p95 yellow, others brand
        const color = b.p99Ms > 0 && val === b.p99Ms && metric === 'p99'
          ? 'var(--crit)'
          : b.p95Ms > 0 && val === b.p95Ms && metric === 'p95'
          ? 'var(--warn)'
          : 'var(--brand-500)';
        return (
          <g key={i}>
            <rect x={x} y={y} width={bw - 4} height={bh} rx="2" fill={color} opacity="0.85" />
            {i % Math.max(1, Math.floor(buckets.length / 10)) === 0 && (
              <text
                x={x + (bw - 4) / 2} y={h - 10}
                fontSize="10.5" fill="var(--text-subtle)"
                fontFamily="var(--font-mono)" textAnchor="middle"
              >
                {b.label}
              </text>
            )}
          </g>
        );
      })}
      {max > 0 && (
        <>
          <line
            x1={pad.left} x2={w - pad.right}
            y1={pad.top + innerH * (1 - p95Line / max)} y2={pad.top + innerH * (1 - p95Line / max)}
            stroke="var(--warn)" strokeDasharray="3 3" opacity="0.7"
          />
          <text
            x={w - pad.right - 4} y={pad.top + innerH * (1 - p95Line / max) - 4}
            fontSize="10.5" fill="var(--warn)" fontFamily="var(--font-mono)" textAnchor="end"
          >
            p95 · {Math.round(p95Line)}ms
          </text>
        </>
      )}
    </svg>
  );
}

