export default function HomePage() {
  const [activeRange, setActiveRange] = useState<RangeLabel>('30D');
  const [perfMetric, setPerfMetric] = useState<'avg' | 'p50' | 'p95' | 'p99'>('avg');

  const days = useMemo(() => RANGES.find(r => r.label === activeRange)?.days ?? 30, [activeRange]);

  const { data: auth } = useAuth();
  const { data: trends, isLoading: trendsLoading, refetch: refetchTrends } = useHomeTrendsQuery(days);
  const { data: activity, isLoading: activityLoading, refetch: refetchActivity } = useHomeActivityQuery();

  const handleRefresh = () => {
    void refetchTrends();
    void refetchActivity();
  };

  // Placeholder for loading state
  const dash = (v: string | number | undefined | null, fallback = '—') =>
    (trendsLoading || v == null) ? fallback : String(v);

  // Delta sign helpers
  const fmtDelta = (n: number, suffix = '') =>
    n >= 0 ? `+${n}${suffix}` : `${n}${suffix}`;

  const fmtPct = (n: number) => n >= 0 ? `+${n.toFixed(1)}%` : `${n.toFixed(1)}%`;

  // Migration overview: derived from data (tasks = unresolved query tasks)
  // These come from the same trends endpoint context for display
  const anomaliesOpen = trends?.anomaliesOpen ?? 0;
  const anomaliesAck = trends?.anomaliesAcknowledged ?? 0;

  // Perf histogram buckets for the selected metric
  const perfBuckets = trends?.perfBuckets ?? [];

  return (
    <div className="page">
      {/* Hero header */}
      <BeaconHero
        displayName={auth?.displayName}
        queryExecutions={trends?.queryExecutions30d ?? 0}
        anomaliesOpen={anomaliesOpen}
        onRefresh={handleRefresh}
      />

      {/* Filter / range bar */}
      <div className="filter-bar">
        <div className="seg" role="tablist">
          {RANGES.map(r => (
            <button
              key={r.label}
              className={`seg__btn${activeRange === r.label ? ' active' : ''}`}
              onClick={() => setActiveRange(r.label)}
              role="tab"
              aria-selected={activeRange === r.label}
            >
              {r.label}
            </button>
          ))}
        </div>
        <div style={{ width: 1, height: 20, background: 'var(--border)' }} />
        <button className="chip"><Icon.Filter size={12} /> All projects</button>
        <button className="chip"><Icon.Database size={12} /> All sources</button>
        <button className="chip"><Icon.Users size={12} /> All users</button>
        <div className="spacer" />
        <button className="icon-btn" title="Calendar"><Icon.Calendar size={15} /></button>
      </div>

      {/* KPI grid */}
      <div className="kpi-grid">
        <Kpi
          dot="brand"
          label="Active subscriptions"
          value={dash(trends?.totalSubscriptions != null ? formatNumber(trends.totalSubscriptions) : null)}
          delta={trends ? fmtDelta(trends.subscriptionDelta) : undefined}
          deltaDir={trends && trends.subscriptionDelta >= 0 ? 'up' : 'down'}
          sub={`${trends?.dataSourcesOnline ?? '—'} sources online`}
          spark={
            !trendsLoading && trends?.subscriptionsSpark ? (
              <Sparkline points={trends.subscriptionsSpark} color="var(--brand-500)" />
            ) : undefined
          }
        />
        <Kpi
          dot="info"
          label="Query executions"
          value={dash(trends?.queryExecutions30d != null ? formatNumber(trends.queryExecutions30d) : null)}
          delta={trends ? fmtPct(trends.queryExecutionsDelta) : undefined}
          deltaDir={trends && trends.queryExecutionsDelta >= 0 ? 'up' : 'down'}
          sub={`last ${days} days`}
          spark={
            !trendsLoading && trends?.queriesSpark ? (
              <Sparkline points={trends.queriesSpark} color="oklch(60% 0.13 240)" />
            ) : undefined
          }
        />
        <Kpi
          dot="warn"
          label="Notifications sent"
          value={dash(trends?.notificationsSent30d != null ? formatNumber(trends.notificationsSent30d) : null)}
          delta={trends ? fmtDelta(trends.notificationsDelta) : undefined}
          deltaDir={trends && trends.notificationsDelta >= 0 ? 'up' : 'down'}
          sub={`${trends?.recipientsCount ?? '—'} recipients`}
          spark={
            !trendsLoading && trends?.notificationsSpark ? (
              <Sparkline points={trends.notificationsSpark} color="oklch(70% 0.15 70)" />
            ) : undefined
          }
        />
        <Kpi
          dot="crit"
          label="Anomalies detected"
          value={dash(anomaliesOpen != null ? formatNumber(anomaliesOpen) : null)}
          delta={trends ? fmtDelta(trends.anomaliesDelta) : undefined}
          deltaDir={trends && trends.anomaliesDelta <= 0 ? 'down' : 'up'}
          intent="crit"
          sub={
            <><span className="pill pill--crit" style={{ marginRight: 6 }}>{anomaliesOpen} open</span>{anomaliesAck} acknowledged</>
          }
          spark={
            !trendsLoading && trends?.anomaliesSpark ? (
              <Sparkline points={trends.anomaliesSpark} color="oklch(60% 0.19 25)" />
            ) : undefined
          }
        />
      </div>

      {/* Performance KPIs */}
      <div className="row row--3-up">
        <PerfKpi
          dot="ok"
          label="Avg execution"
          value={trends ? Math.round(trends.avgExecutionMs).toLocaleString() : '—'}
          unit="ms"
          sub="across all queries"
          delta={trends ? fmtPct(trends.avgExecutionDeltaPct) : undefined}
          deltaDir={trends && trends.avgExecutionDeltaPct <= 0 ? 'down' : 'up'}
        />
        <PerfKpi
          dot="ok"
          label="Fastest query"
          value={trends?.fastestQueryMs ? Math.round(trends.fastestQueryMs).toLocaleString() : '—'}
          unit="ms"
          sub={
            trends?.fastestQueryName
              ? <><span className="mono">{trends.fastestQueryName}</span></>
              : <span className="muted">no data</span>
          }
        />
        <PerfKpi
          dot="warn"
          label="Slowest query"
          value={trends?.slowestQueryMs ? Math.round(trends.slowestQueryMs).toLocaleString() : '—'}
          unit="ms"
          sub={
            trends?.slowestQueryName
              ? <><span className="mono">{trends.slowestQueryName}</span></>
              : <span className="muted">no data</span>
          }
        />
      </div>

      {/* Activity trends + system overview */}
      <div className="row row--7-3">
        <div className="card">
          <div className="card__head">
            <Icon.Trend size={15} className="muted" />
            <h3 className="card__title">Activity trends</h3>
            <span className="card__sub">last {days} days</span>
            <div className="card__actions">
              <div className="legend">
                <span className="legend__item">
                  <span className="legend__sw" style={{ background: 'var(--brand-500)' }} />
                  Queries executed
                </span>
                <span className="legend__item">
                  <span className="legend__sw" style={{ background: 'oklch(70% 0.15 70)' }} />
                  Notifications sent
                </span>
              </div>
            </div>
          </div>
          <div className="chart-wrap">
            <LineChart
              days={days}
              series={[
                { name: 'Queries', color: 'var(--brand-500)', data: trends?.queryTrend30d ?? [] },
                { name: 'Notifs', color: 'oklch(70% 0.15 70)', data: trends?.notificationsTrend30d ?? [] },
              ]}
            />
          </div>
        </div>

        <div className="card">
          <div className="card__head">
            <Icon.Layers size={15} className="muted" />
            <h3 className="card__title">System overview</h3>
            <div className="card__actions">
              <span className="pill pill--ok">
                <span style={{ width: 6, height: 6, borderRadius: 99, background: 'var(--ok)' }} />
                {' '}Healthy
              </span>
            </div>
          </div>
          <div className="stat-list">
            <StatRow
              icon="Database"
              label="Data sources"
              value={trendsLoading ? '—' : formatNumber(trends?.dataSourcesOnline ?? 0)}
              trail={<span className="pill pill--ok">{trendsLoading ? '—' : trends?.dataSourcesOnline} online</span>}
            />
            <StatRow
              icon="Users"
              label="Recipients"
              value={trendsLoading ? '—' : formatNumber(trends?.recipientsCount ?? 0)}
            />
            <StatRow
              icon="Check"
              label="Active subscriptions"
              value={trendsLoading ? '—' : formatNumber(trends?.totalSubscriptions ?? 0)}
            />
            <StatRow
              icon="Alert"
              label="Active anomalies"
              value={trendsLoading ? '—' : formatNumber(anomaliesOpen)}
              trail={anomaliesOpen > 0 ? <span className="pill pill--crit">action req.</span> : undefined}
            />
            <StatRow
              icon="Plug"
              label="Integrations"
              value={trendsLoading ? '—' : formatNumber(trends?.integrationsCount ?? 0)}
              trail={<span className="mono subtle">channel types</span>}
            />
          </div>
        </div>
      </div>

      {/* Query exec performance histogram */}
      <div className="card">
        <div className="card__head">
          <Icon.Bolt size={15} className="muted" />
          <h3 className="card__title">Query execution performance</h3>
          <span className="card__sub">last {days} days · all sources</span>
          <div className="card__actions">
            <div className="seg">
              {(['avg', 'p50', 'p95', 'p99'] as const).map(m => (
                <button
                  key={m}
                  className={`seg__btn${perfMetric === m ? ' active' : ''}`}
                  onClick={() => setPerfMetric(m)}
                >
                  {m}
                </button>
              ))}
            </div>
          </div>
        </div>
        <div className="chart-wrap">
          <PerfHistogram buckets={perfBuckets} metric={perfMetric} />
        </div>
        <div style={{ display: 'flex', gap: 16, padding: '0 16px 14px', alignItems: 'center', flexWrap: 'wrap' }}>
          <span className="legend__item legend"><span className="legend__sw" style={{ background: 'var(--brand-500)' }} />typical</span>
          <span className="legend__item legend"><span className="legend__sw" style={{ background: 'var(--warn)' }} />p95 spike</span>
          <span className="legend__item legend"><span className="legend__sw" style={{ background: 'var(--crit)' }} />p99 spike</span>
        </div>
      </div>

      {/* Bottom row: left column (migration + tasks) + right (activity feed) */}
      <div className="row row--7-3">
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          {/* Data migration overview — derived from anomalies/executions stats */}
          <MigrationOverviewCard />

          {/* Task management */}
          <TaskMgmtCard />
        </div>

        {/* Recent activity feed */}
        <div className="card">
          <div className="card__head">
            <Icon.Activity size={15} className="muted" />
            <h3 className="card__title">Recent activity</h3>
            <div className="card__actions">
              <Link to="/control-tower" style={{ fontSize: 12.5, color: 'var(--brand-600)', textDecoration: 'none', fontWeight: 500 }}>View all →</Link>
            </div>
          </div>
          <div className="feed">
            {activityLoading && (
              <div style={{ padding: '20px 16px', color: 'var(--text-subtle)', fontSize: 13 }}>Loading…</div>
            )}
            {!activityLoading && (!activity?.items || activity.items.length === 0) && (
              <div style={{ padding: '24px 16px', textAlign: 'center' }}>
                <Icon.Activity size={20} className="muted" />
                <p style={{ marginTop: 8, fontSize: 13, color: 'var(--text-subtle)' }}>No recent activity</p>
              </div>
            )}
            {!activityLoading && activity?.items.map((item: HomeActivityItem, i: number) => (
              <FeedItem
                key={i}
                tone={item.tone}
                icon={item.icon}
                title={item.title}
                meta={item.meta ?? undefined}
                time={relativeTime(item.timestamp)}
              />
            ))}
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="row-spread" style={{ paddingTop: 4 }}>
        <span className="mono subtle" style={{ fontSize: 11.5 }}>
          Beacon · region eu-west
        </span>
        <span className="mono subtle" style={{ fontSize: 11.5 }}>
          Press <span className="kbd">⌘</span> <span className="kbd">K</span> to search
        </span>
      </div>
    </div>
  );
}

// ── Migration overview card ───────────────────────────────────────────────────

function MigrationOverviewCard() {
  const { data, isLoading } = useHomeMigrationSummaryQuery();

  const total = data?.total ?? 0;
  const successful = data?.successful ?? 0;
  const executions = data?.executions ?? 0;
  const errored = data?.errored ?? 0;
  const successPct = total > 0 ? Math.round((successful / total) * 100) + '%' : '0%';
  const execPct = total > 0 ? Math.min(100, Math.round((executions / Math.max(total * 10, 1)) * 100)) + '%' : '0%';
  const errorPct = total > 0 ? Math.round((errored / total) * 100) + '%' : '0%';

  return (
    <div className="card">
      <div className="card__head">
        <Icon.ArrowsLR size={15} className="muted" />
        <h3 className="card__title">Data migration</h3>
        <span className="card__sub">overview</span>
        <div className="card__actions">
          <Link to="/migration-history" style={{ fontSize: 12.5, color: 'var(--brand-600)', textDecoration: 'none', fontWeight: 500 }}>
            Open jobs →
          </Link>
        </div>
      </div>
      <div className="card__body card__body--flush">
        <div className="mini-grid">
          <Mini dot="var(--info)" label="Total jobs" value={isLoading ? '—' : formatNumber(total)} bar="100%" barColor="var(--info)" />
          <Mini dot="var(--ok)" label="Successful" value={isLoading ? '—' : formatNumber(successful)} bar={successPct} barColor="var(--ok)" />
          <Mini dot="var(--brand-500)" label="Executions" value={isLoading ? '—' : formatNumber(executions)} bar={execPct} barColor="var(--brand-500)" />
          <Mini dot="var(--crit)" label="Errored" value={isLoading ? '—' : formatNumber(errored)} bar={errorPct} barColor="var(--crit)" />
        </div>
      </div>
    </div>
  );
}

function TaskMgmtCard() {
  const { data, isLoading } = useHomeTaskSummaryQuery();

  const total = data?.total ?? 0;
  const open = data?.open ?? 0;
  const resolved = data?.resolved ?? 0;
  const openPct = total > 0 ? Math.round((open / total) * 100) + '%' : '0%';
  const resolvedPct = total > 0 ? Math.round((resolved / total) * 100) + '%' : '0%';

  return (
    <div className="card">
      <div className="card__head">
        <Icon.Check size={15} className="muted" />
        <h3 className="card__title">Task management</h3>
        <span className="card__sub">{isLoading ? '—' : `${open} unresolved`}</span>
      </div>
      <div className="card__body card__body--flush">
        <div className="mini-grid mini-grid--3">
          <Mini dot="var(--text-muted)" label="Total" value={isLoading ? '—' : formatNumber(total)} bar="100%" barColor="var(--text-muted)" />
          <Mini dot="var(--warn)" label="Open" value={isLoading ? '—' : formatNumber(open)} bar={openPct} barColor="var(--warn)" />
          <Mini dot="var(--ok)" label="Resolved" value={isLoading ? '—' : formatNumber(resolved)} bar={resolvedPct} barColor="var(--ok)" />
        </div>
      </div>
    </div>
  );
}

// ── Local wrappers calling proper query hooks ─────────────────────────────────

function useHomeMigrationSummaryQuery() {
  return useQuery({
    queryKey: ['home', 'migration-summary'],
    queryFn: () => fetchJson<GetHomeMigrationSummaryResult>('/beacon/api/home/migration-summary'),
    retry: false,
  });
}

function useHomeTaskSummaryQuery() {
  return useQuery({
    queryKey: ['home', 'task-summary'],
    queryFn: () => fetchJson<GetHomeTaskSummaryResult>('/beacon/api/home/task-summary'),
    retry: false,
  });
}
